// 사용자 질문 → LLM 요청 본문(few-shot + json_schema) 구성
const q = $json.chatInput || $json.chatMessage || "";
const schema = { type:"object", additionalProperties:false, properties:{
  keyword:{type:"string"}, tech:{type:"array",items:{type:"string"}}, maxCareer:{type:"integer"},
  source:{type:"string",enum:["any","jumpit","wanted"]}, company:{type:"string"}, days:{type:"integer"},
  mode:{type:"string",enum:["list","count"]}, limit:{type:"integer"} },
  required:["keyword","tech","maxCareer","source","company","days","mode","limit"] };
const body = { model:"kanana-1.5-8b-instruct-2505-mlx",
  messages:[{role:"system",content:"채용공고 검색 질문을 필터 JSON으로 변환한다.
- keyword: 직무/역할 단어(백엔드,프론트엔드,AI,PM 등). 없으면 ""
- tech: 기술스택(Redis,Kafka,Java 등). 없으면 []
- maxCareer: "N년 이하"→N, "신입"→0, 없으면 -1
- source: "원티드"→wanted, "점프잇/잡핏"→jumpit, 없으면 any
- company: 회사명. 없으면 ""
- days: "이번 주"→7, "오늘"→1, "이번 달"→30, 없으면 0
- mode: "몇 개/개수" 물으면 count, 아니면 list
- limit: "N개 보여줘"의 N, 기본 20

예시:
Q: 3년 이하 백엔드 중 Redis 쓰는 곳
A: {"keyword":"백엔드","tech":["Redis"],"maxCareer":3,"source":"any","company":"","days":0,"mode":"list","limit":20}
Q: 원티드에서 이번 주 AI 공고 몇 개야?
A: {"keyword":"AI","tech":[],"maxCareer":-1,"source":"wanted","company":"","days":7,"mode":"count","limit":20}
Q: 프론트엔드 10개 보여줘
A: {"keyword":"프론트엔드","tech":[],"maxCareer":-1,"source":"any","company":"","days":0,"mode":"list","limit":10}"},{role:"user",content:q}],
  temperature:0.1, max_tokens:300, tools:[],
  response_format:{type:"json_schema", json_schema:{name:"job_filter", schema}} };
return [{ json: { body, chatInput: q } }];

// LLM이 뽑은 필터 JSON → 안전한 SELECT SQL (모든 문자열 이스케이프, SELECT만).
let f;
try { f = JSON.parse($json.choices?.[0]?.message?.content || '{}'); } catch (e) { f = {}; }
const esc = (s) => String(s).replace(/'/g, "''");
const where = ["status='done'"];
if (f.keyword) where.push(`title ILIKE '%${esc(f.keyword)}%'`);
if (f.company) where.push(`company ILIKE '%${esc(f.company)}%'`);
if (Array.isArray(f.tech) && f.tech.length) {
  const conds = f.tech.map(t => `EXISTS (SELECT 1 FROM unnest(tech_stacks) s WHERE s ILIKE '%${esc(t)}%')`);
  where.push('(' + conds.join(' AND ') + ')');
}
if (Number.isInteger(f.maxCareer) && f.maxCareer >= 0) where.push(`(min_career IS NULL OR min_career <= ${f.maxCareer})`);
if (f.source === 'jumpit' || f.source === 'wanted') where.push(`source='${f.source}'`);
if (Number.isInteger(f.days) && f.days > 0) where.push(`collected_at > now() - interval '${f.days} days'`);
const limit = Math.min(Math.max(Number(f.limit) || 20, 1), 50);
const whereSql = where.join(' AND ');
const sql = (f.mode === 'count')
  ? `SELECT count(*) AS cnt FROM jobs WHERE ${whereSql};`
  : `SELECT source, title, company, min_career, max_career, tech_stacks, url, summary FROM jobs WHERE ${whereSql} ORDER BY collected_at DESC LIMIT ${limit};`;
return [{ json: { sql, mode: f.mode || 'list', filter: f } }];

// Postgres 결과 → 챗 응답 텍스트
const mode = $('SQL 생성').first().json.mode;
const rows = $input.all();
let text;
if (mode === 'count') {
  text = `🔎 조건에 맞는 공고: **${rows[0]?.json?.cnt ?? 0}건**`;
} else if (rows.length === 0) {
  text = '🔎 조건에 맞는 공고가 없어요. (요약 완료된 공고만 검색됩니다)';
} else {
  text = `🔎 **${rows.length}건** 찾았어요\n\n`;
  for (const r of rows) {
    const m = r.json;
    const career = [m.min_career, m.max_career].filter(v => v != null).join('~') || '무관';
    const stacks = Array.isArray(m.tech_stacks) ? m.tech_stacks.join(', ') : '';
    text += `**${m.company} — ${m.title}** (경력 ${career})\n${stacks || '-'}\n${m.url}\n\n`;
  }
}
return [{ json: { output: text, text } }];
